import React from "react";

const About = () => {
  return (
    <section className="py-20 bg-slate-50 px-6">
      <div className="max-w-4xl mx-auto text-center">
        <h2 className="text-3xl font-bold mb-6">About Karo Pitch</h2>
        <p className="text-lg text-slate-700 leading-relaxed mb-6">
          Thousands of founders are building amazing businesses across Bharat
          but lack access to investors. Karo Pitch connects these founders with
          investors through curated pitch events and a discovery platform.
        </p>
        <p className="text-lg text-slate-700 leading-relaxed mb-6">
          Powered by KaroStartup, our mission is to build India’s most
          accessible startup discovery and funding platform, bridging the gap
          between real businesses and the capital they need to scale.
        </p>
      </div>
    </section>
  );
};

export default About;
